type rowX = f5.Row

func fold_b(a []rowX, b uint64) ([]rowX, error) {
        out := make([]rowX, len(a))
        copy(out, a)
        sort.SliceStable(out, func(i, j int) bool {
                return out[i].Seq < out[j].Seq
        })

        // Rows represent an append-only history. Even when simulating a restart,
        // we must preserve sequence order so that the last write wins and the
        // restored tree matches the final on-disk source state.
